    private fun ASTNode?.isLastElementOnLine() = this == null || (elementType == WHITE_SPACE && textContains('\n'))

    private fun isBlockCommentInSingleLineBlock(
        precedingLeaf: ASTNode?,
        followingLeaf: ASTNode?,
    ): Boolean {
        val actualPreceding =
            if (precedingLeaf?.elementType == WHITE_SPACE) {
                precedingLeaf.prevLeaf()
            } else {
                precedingLeaf
            }
