            if (followingLeaf?.elementType == WHITE_SPACE) {
                followingLeaf.nextLeaf()
            } else {
                followingLeaf
            }
        return actualPreceding?.elementType == LBRACE && actualFollowing?.elementType == RBRACE
    }
}"}

{"file_path": "/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/CommentWrappingRuleSingleLineBlockTest.kt", "content": "package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class CommentWrappingRuleSingleLineBlockTest {
    private val commentWrappingRuleAssertThat = assertThatRule { CommentWrappingRule() }

    @Test
    fun `Given a single line block containing only a block comment then do not report error`() {
        val code =
            """
            val foo = { /* no-op */ }
            """.trimIndent()
        commentWrappingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a single line block containing a block comment without surrounding spaces then do not report error`() {
        val code =
            """
            val foo = {/* no-op */}
            """.trimIndent()
        commentWrappingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a single line lambda in function call containing a block comment then do not report error`() {
        val code =
            """
            fun bar(block: () -> Unit) = block()
            fun test() {
                bar { /* no-op */ }
            }
            """.trimIndent()
        commentWrappingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a single line lambda with block comment as parameter then do not report error`() {
        val code =
            """
            val list = listOf(1, 2, 3).filter { /* always true */ true }
            """.trimIndent()
        commentWrappingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a block comment in between code elements outside curly braces then still report error`() {
        val code =
            """
            val foo /* some comment */ = "foo"
            """.trimIndent()
        commentWrappingRuleAssertThat(code)
            .hasLintViolationWithoutAutoCorrect(
                1,
                9,
                "A block comment in between other elements on the same line is disallowed",
            )
    }
}
"}

